import{_ as t,o as e,c as o,aj as r}from"./chunks/framework.DNJ2HNkG.js";const c=JSON.parse('{"title":"知识星球","description":"","frontmatter":{"title":"知识星球","date":"2023-12-21T21:38:54.000Z","category":"Home","tags":["知识"]},"headers":[],"relativePath":"posts/知识星球.md","filePath":"posts/知识星球.md","lastUpdated":1783047625000}'),p={name:"posts/知识星球.md"};function s(i,a,n,l,_,d){return e(),o("div",null,[...a[0]||(a[0]=[r(`<h1 id="_0x01-引言" tabindex="-1">0x01 引言 <a class="header-anchor" href="#_0x01-引言" aria-label="Permalink to &quot;0x01 引言&quot;">​</a></h1><p>马上就2024了，在2023年迎来了三宝的到来，大宝也开始了小学生涯，生活的鸭梨更大了一些。在各位兄弟的帮助下，买下了大一点的房子，以后在家里也能有个小实验室了，虽然距离B站创始人的实验室还有若干差距，但至少有了一个好的开始，不是么^_^</p><pre><code>[探秘！B站联合创始人的《钞能力实验室》]（https://www.bilibili.com/video/BV1bu4y1w7dh/)
</code></pre><h1 id="_0x02-目标" tabindex="-1">0x02 目标 <a class="header-anchor" href="#_0x02-目标" aria-label="Permalink to &quot;0x02 目标&quot;">​</a></h1><p>2024年，会更聚焦于硬件安全方向，欠下来的债要还，挖的坑要填，2023年还是折腾了不少东西的，但都因为种种原因没有展示出来发布出来，24年会酌情放出。</p><p>CUBE是很多朋友期待了很久的极客玩具，我会尽早设计完善出来，经过了这么多年，科技一直在进步，CUBE的芯片方案、功能需求其实也一直在迭代优化，加上自己的想法也很杂散，所以一直做做停停改改，一直没有让自己满意，希望在24年能和大家见面，拖延症不能再拖了。。。</p><h1 id="_0x03-知识星球" tabindex="-1">0x03 知识星球 <a class="header-anchor" href="#_0x03-知识星球" aria-label="Permalink to &quot;0x03 知识星球&quot;">​</a></h1><p>曾经架设了IoT Craftsman论坛，但发现论坛这种形式已经没落了，微信、QQ等即时聊天工具又太零散，又不是电商搞私域运营，而Blog终究只是个信息发布平台，在简单调研了几个平台后，决定还是启用曾经创建的知识星球。</p><p><strong>这个知识星球，有年费门槛，经济状况不允许的朋友请优先保障生活质量！</strong></p><p>主要会分享一些IT数码电子、IoT硬件无线电安全等方向的教程、文章、文件等，频率不会太高。</p><p>目前给自己定的要求是： 1、每月至少更新1篇原创文章 2、每周都要抽时间出来回答提问</p><p>此外，等新房子装修空置好，搬家之前要清理一大批乱七八糟的设备，打算作为抽奖奖品发给成员~~ 所以如果加入了星球，务必登记好信息。</p><p><strong>成员超过50就开始抽奖╰(<em>°▽°</em>)╯</strong></p><h1 id="_0x04-未来" tabindex="-1">0x04 未来 <a class="header-anchor" href="#_0x04-未来" aria-label="Permalink to &quot;0x04 未来&quot;">​</a></h1><p>看知识星球的实际运营情况吧，也会邀请合伙人、嘉宾或者管理员来一起分享。</p><p>至于cube之类的产品后续如果有产出有交互，到时候再看是以论坛还是交流群还是星球的方式运营。</p><h1 id="_0x05-最后" tabindex="-1">0x05 最后 <a class="header-anchor" href="#_0x05-最后" aria-label="Permalink to &quot;0x05 最后&quot;">​</a></h1><p>这个Blog还会继续存在，以后也还会继续更新分享一些文章教程，只不过会比星球有一定延迟而已【感谢打赏过的朋友】。</p><p>虽然过去了那么多年，虽然已经是三个孩子的父亲，也早就不孤独了，但我还是我，&quot;不孤独&quot; 的 &quot;小白&quot;，继续保持谦卑的心态，不忘初心，方得始终。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E7%9F%A5%E8%AF%86%E6%98%9F%E7%90%83/1703167156373.jpg" alt="知识星球"></p>`,20)])])}const x=t(p,[["render",s]]);export{c as __pageData,x as default};
